/* Mini syntax highlighter — keywords/strings/comments/numbers */
(function(){
"use strict";
var KW=/\b(fn|let|mut|const|pub|use|mod|struct|enum|impl|trait|type|where|async|await|return|if|else|for|while|loop|match|break|continue|true|false|self|Self|super|crate|as|in|ref|move|dyn|static|extern|unsafe|function|var|class|import|export|from|require|def|print|elif|pass|with|yield|lambda|try|except|finally|raise|None|True|False|int|str|float|list|dict|package|func|go|defer|chan|select|case|switch|default|interface|map|range|make|new|throw|catch|extends|implements|abstract|final|public|private|protected|void|null|this|override|val|object|companion|data|sealed|when|do|end|then|elsif|unless|nil|puts|module|begin|rescue|ensure|include|echo|fi|done|esac|local|declare|not|and|or|is|del|assert|global|nonlocal)\b/g;
var ST=/(["'`])(?:(?!\1|\\).|\\.)*?\1/g;
var CM=/\/\/.*|#[^\[!].*|\/\*[\s\S]*?\*\//g;
var NM=/\b0x[\da-fA-F]+\b|\b\d+\.?\d*(?:e[+-]?\d+)?\b/g;
var FN=/\b([a-zA-Z_]\w*)\s*(?=\()/g;
function esc(s){return s.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");}
function hi(code){
var t=[],id=0;
function ph(s){var k="%%"+id+"%%";t.push(s);id++;return k;}
code=esc(code);
code=code.replace(CM,function(m){return ph('<span class="hlc">'+m+"</span>");});
code=code.replace(ST,function(m){return ph('<span class="hls">'+m+"</span>");});
code=code.replace(FN,function(_,n){KW.lastIndex=0;return KW.test(n)?_:ph('<span class="hlf">'+n+"</span>")+"(";});
KW.lastIndex=0;
code=code.replace(KW,'<span class="hlk">$&</span>');
code=code.replace(NM,'<span class="hln">$&</span>');
for(var i=t.length-1;i>=0;i--)code=code.replace("%%"+i+"%%",t[i]);
return code;}
function run(){var b=document.querySelectorAll("pre code");for(var i=0;i<b.length;i++){var e=b[i];if(!e.dataset.hl){e.innerHTML=hi(e.textContent);e.dataset.hl="1";}}}
window.hljs={highlightAll:run};
if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",run);else run();
})();
